import React, { useEffect, useState } from 'react';
import './styles/index.css';

function App() {
    const [theme, setTheme] = useState('light');

    useEffect(() => {
        document.body.className = theme;
    }, [theme]);

    useEffect(() => {
        const sections = document.querySelectorAll('.section');
        const observer = new IntersectionObserver(
            (entries) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add('visible');
                    }
                });
            },
            { threshold: 0.1 }
        );

        sections.forEach((section) => observer.observe(section));
    }, []);

    const toggleTheme = () => {
        setTheme((prevTheme) => (prevTheme === 'light' ? 'dark' : 'light'));
    };

    return (
        <div className="container">
            <header>
                <h1>Bilal Ahmed</h1>
                <p>Email: mr.bilal.ahmed281@gmail.com | Phone: +92 (318)-7584281 | Address: Mianwali, Pakistan</p>
                <button className="theme-toggle" onClick={toggleTheme}>
                    Toggle Theme
                </button>
            </header>

            <div className="section">
                <h2>Objective</h2>
                <p>
                    Experienced Software Engineer with a demonstrated history of working in the information technology
                    industry. Skilled in Python, C++, JavaScript, React. Strong engineering professional with a
                    Bachelor’s Degree focused in Software Engineering from The University of Mianwali.
                </p>
            </div>

            <div className="section">
                <h2>Education</h2>
                <ul>
                    <li>
                        <strong>Bachelor of Science in Software Engineering</strong> - The University of Mianwali
                        (2022-2026)
                        <p>CGPA: 2.77/4.0</p>
                    </li>
                    <li>
                        <strong>HSSC</strong> - The Superior Group of Colleges, Pakistan (2020-2022)
                        <p>Marks: 815/1100</p>
                    </li>
                    <li>
                        <strong>SSC</strong> - Govt. High School, Shadia, Pakistan (2018-2020)
                        <p>Marks: 911/1100</p>
                    </li>
                </ul>
            </div>

            <div className="section">
                <h2>Projects</h2>
                <ul>
                    <li>
                        <strong>Spotify Clone</strong> - HTML, CSS, JavaScript
                        <p>Built a front-end clone of Spotify with a stylish UI and responsive layout.</p>
                    </li>
                    <li>
                        <strong>University Challan Generator</strong> - PHP, MySQL, HTML, CSS
                        <p>Developed a system to generate student fee challans dynamically.</p>
                    </li>
                    <li>
                        <strong>Bakery Management System</strong> - PHP, MySQL, JavaScript
                        <p>Created a web app for managing bakery products, orders, and stock.</p>
                    </li>
                    <li>
                        <strong>Swift Converter (Ongoing)</strong> - HTML, CSS, JavaScript, PHP
                        <p>Multi-functional web app to convert PDF ↔ Word/Image, Image ↔ Text, etc.</p>
                    </li>
                </ul>
            </div>

            <div className="section">
                <h2>Skills</h2>
                <ul>
                    <li>Operating Systems: Linux (Kali, Ubuntu), Windows</li>
                    <li>Languages: Python, C++, HTML, CSS, JavaScript, PHP, MySQL, ReactJS</li>
                    <li>Tools: VS Code, MS Office, Git & GitHub</li>
                    <li>Web Frameworks: Bootstrap, Flask, OpenCV, TensorFlow, FastAPI, ReactJS</li>
                    <li>Databases: SQL Server, MySQL, XAMPP Server</li>
                </ul>
            </div>

            <div className="section">
                <h2>Honors and Awards</h2>
                <ul>
                    <li>Successfully completed the DELTA BATCH Full Stack Development on Apna College, India.</li>
                    <li>Participated in the GENZ CODING QUEST Coding Competition at University of Mianwali.</li>
                    <li>Participated in First Frontiers in Computational Intelligence & Data Science Conference 2025.</li>
                    <li>3rd Open International Internet Ecology Olympiad.</li>
                    <li>Police and Rescue Training at University of Mianwali and Police station, Mianwali.</li>
                </ul>
            </div>

            <footer>
                <p>&copy; 2025 Bilal Ahmed. All rights reserved.</p>
            </footer>
        </div>
    );
}

export default App;
